export interface Article {
  id: string;
  title: string;
  category: string;
  imageUrl: string;
  excerpt: string;
  date: string;
  author: string;
  content: string; // HTML format for long-form content
}

export const getArticleImageUrl = (article: Article) => {
  // If we have a direct modern unsplash URL, use it
  if (article.imageUrl && (article.imageUrl.includes('images.unsplash.com') || article.imageUrl.includes('fbcdn.net'))) {
    return article.imageUrl;
  }

  // Pool of high-quality business/tax/accounting related Unsplash IDs
  const fallbackImages = [
    '1554224155-6726b3ff858f', '1454165833222-381a25244510', '1589823436324-42998a4da8d3', '1450101499163-c8848c66ca85',
    '1554224154-26032ffc0d07', '1460925895917-afdab827c52f', '1560518883-ce09059eeffa', '1497366216548-37526070297c',
    '1507679799987-c7377f0da46', '1454165205734-3a731d40dc4e', '1516321318423-f06f85e504b3', '1553729459-efe14ef6055d',
    '1579621970563-ebec7560ff3e', '1542744173-8e7e53415bb0', '1556740758-90de374c12ad', '1519389950473-47ba0277781c',
    '1521791136064-7986c295944b', '1551836022-d5d88e9218df', '1544377193-33dcf4d68fb5', '1512428559083-560df5f8b955',
    '1520607162513-77705c0f0d4a', '1454165205734-3a731d40dc4e', '1504384308090-c894fdcc538d', '1486406146926-c627a92ad1ab',
    '1554415707-6e8cfc93fe23', '1557804506-669a67965ba0', '1522202176988-66273c2fd55f', '1523240795612-9a054b0db644'
  ];

  // More robust hash function for deterministic index
  let hash = 0;
  const str = article.id + article.title;
  for (let i = 0; i < str.length; i++) {
    hash = (hash << 5) - hash + str.charCodeAt(i);
    hash |= 0; // Convert to 32bit integer
  }
  
  const index = Math.abs(hash) % fallbackImages.length;
  return `https://images.unsplash.com/photo-${fallbackImages[index]}?auto=format&fit=crop&q=80&w=800`;
};

